// ============================================================
// Extraer predicciones desde mensaje de Telegram
// Entrada: el JSON del mensaje enviado por el bot
// Salida: mismo formato que antes para Supabase
// ============================================================

// ── 1. Obtener el texto del mensaje ──
const inputData = $input.first().json;
const messageText = inputData.result?.text || inputData.text || '';

if (!messageText) {
  throw new Error('No se encontró texto del mensaje de Telegram');
}

// ── 2. Función para extraer datos de un modelo (Llama o Mistral) ──
function extraerModelo(texto, nombreModelo) {
  // Buscar el bloque del modelo: "🔷 Llama 70b (35%)" o "🔷 Mistral (40%)"
  const regexModelo = new RegExp(`🔷 ${nombreModelo.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\s*\\((\\d+)%\\)`, 'i');
  const matchModelo = texto.match(regexModelo);
  if (!matchModelo) return null;

  const confianza = parseInt(matchModelo[1], 10);

  // Extraer la línea de la secuencia: "🕐 08AM:0 → 09AM:22 → ..."
  const secuenciaRegex = /🕐\s+([\d:AMPM]+:\d+(?:\s*→\s*[\d:AMPM]+:\d+)*)/i;
  const secuenciaMatch = texto.match(secuenciaRegex);
  if (!secuenciaMatch) return null;

  const secuenciaRaw = secuenciaMatch[1];
  // Parsear "08AM:0 → 09AM:22 → 10AM:32 ..."
  const partes = secuenciaRaw.split(/\s*→\s*/);
  const secuencia = {};
  for (const parte of partes) {
    const [hora, numero] = parte.split(':');
    if (hora && numero !== undefined) {
      secuencia[hora.trim()] = numero.trim();
    }
  }

  // Extraer enjaulados: "🐘 Enjaulados: 0, 8, 31"
  const enjauladosRegex = /🐘\s*Enjaulados:\s*([\d,\s]+)/i;
  const enjauladosMatch = texto.match(enjauladosRegex);
  let enjaulados = [];
  if (enjauladosMatch) {
    enjaulados = enjauladosMatch[1].split(',').map(s => s.trim()).filter(n => n);
  }

  return {
    modelo: nombreModelo,
    secuencia: secuencia,
    enjaulados_usados: enjaulados,
    confianza: confianza,
    ok: true
  };
}

// ── 3. Extraer ambos modelos ──
const modeloLlama = extraerModelo(messageText, 'Llama 70b');
const modeloMistral = extraerModelo(messageText, 'Mistral');

const resultados = [];
if (modeloLlama) resultados.push(modeloLlama);
if (modeloMistral) resultados.push(modeloMistral);

if (resultados.length === 0) {
  throw new Error('No se pudieron extraer los modelos del mensaje');
}

// ── 4. Salida para Supabase (igual que antes) ──
const now = new Date();
const venezuelaOffset = -4 * 60 * 60 * 1000; // UTC-4
const horaPrediccion = new Date(now.getTime() + venezuelaOffset)
  .toISOString()
  .slice(11, 16); // "HH:MM"

return [{
