    }
  });
}

return resultados;

// ════════════════════════════════════════════════
// COMPARAR MODELOS — Llama 70b vs Mistral
// ════════════════════════════════════════════════

const HORAS = ["08AM","09AM","10AM","11AM","12PM","01PM","02PM","03PM","04PM","05PM","06PM","07PM"];

// ── 1. Función para limpiar y parsear el JSON que devuelve cada modelo ──
function parsearRespuestaModelo(texto) {
  if (!texto || typeof texto !== 'string') return null;
  try {
    let limpio = texto
      .replace(/<think>[\s\S]*?<\/think>/gi, '')  // quita bloques <think> de modelos tipo reasoning
      .replace(/```json\s*/gi, '')                 // quita ```json
      .replace(/```\s*/gi, '')                     // quita ```
      .trim();

    const inicio = limpio.indexOf('{');
    if (inicio === -1) return { error: 'No se encontró JSON' };

    // Encuentra el cierre correcto del objeto raíz
    let nivel = 0, fin = -1;
    for (let i = inicio; i < limpio.length; i++) {
      if (limpio[i] === '{') nivel++;
      if (limpio[i] === '}') nivel--;
      if (nivel === 0) { fin = i; break; }
    }
    if (fin === -1) return { error: 'JSON incompleto' };

    limpio = limpio.substring(inicio, fin + 1)
      .replace(/:\s*NaN/g, ': null')
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');

    return JSON.parse(limpio);

  } catch (e) {
    return { error: 'Parse fallido: ' + e.message, raw: texto.substring(0, 300) };
  }
}

// ── 2. Normalizar confianza ──
function normalizarConfianza(valor) {
  if (valor === null || valor === undefined) return 0;
  const n = parseFloat(valor);
  return isNaN(n) ? 0 : (n <= 1 ? Math.round(n * 100) : Math.round(n));
}

// ── 3. Extraer y normalizar secuencia ──
function extraerSecuencia(modelo) {
  if (!modelo || modelo.error || !modelo.secuencia) return null;
  const sec = {};
  for (const [hora, valor] of Object.entries(modelo.secuencia)) {
    sec[hora] = String(valor).trim();
  }
  return sec;
}

// ── 4. Obtener textos de respuesta de los nodos Llama y Mistral ──
// Asegúrate de que los nodos en n8n se llamen exactamente "Llama 70B" y "Mistral"
const textoLlama = $('Llama 70B').item.json.text  ?? $('Llama 70B').item.json.output ?? '';
const textoMistral = $('Mistral').item.json.text  ?? $('Mistral').item.json.output ?? '';

const parsedLlama = parsearRespuestaModelo(textoLlama);
const parsedMistral = parsearRespuestaModelo(textoMistral);

// ── 5. Armar objeto por modelo ──
function armarModelo(parsed, nombre) {
  if (!parsed || parsed.error) {
    return {
      modelo:    nombre,
      ok:        false,
      error:     parsed?.error ?? 'Sin datos',
      raw:       parsed?.raw   ?? ''
    };
  }
  return {
    modelo:        nombre,
    ok:            true,
    secuencia:     extraerSecuencia(parsed)  ?? {},
    enjaulados:    (parsed.enjaulados_usados ?? []).map(String),
    confianza:     normalizarConfianza(parsed.confianza),
    logica:        parsed.logica             ?? '',
    razonamiento:  parsed.razonamiento_paso_a_paso ?? parsed.razonamiento ?? ''
  };
}

const modeloLlama = armarModelo(parsedLlama, 'Llama 70b');
const modeloMistral = armarModelo(parsedMistral, 'Mistral');

// ── 6. Comparación hora a hora ──
let coincidencias = 0;
const comparacion = {};

HORAS.forEach(h => {
  const vLlama = modeloLlama.secuencia?.[h] ?? null;
  const vMistral = modeloMistral.secuencia?.[h] ?? null;
  const match = vLlama !== null && vMistral !== null && vLlama === vMistral;

  if (match) coincidencias++;

  comparacion[h] = {
    llama70b: vLlama   ?? '-',
    mistral:  vMistral ?? '-',
    match:    match
  };
});

// ── 7. Horas donde coinciden ──
const horasMatch = HORAS.filter(h => comparacion[h].match);

// ── 8. Secuencia consenso (Gana el modelo con mayor confianza si no hay match) ──
const modeloLider = modeloLlama.confianza >= modeloMistral.confianza ? modeloLlama : modeloMistral;

const secuenciaConsenso = {};
HORAS.forEach(h => {
  secuenciaConsenso[h] = comparacion[h].match
    ? comparacion[h].llama70b             
    : (modeloLider.secuencia?.[h] ?? '-'); 
});

// ── 9. Confianza promedio ──
const modelosOK = [modeloLlama, modeloMistral].filter(m => m.ok);
const confianzaPromedio = modelosOK.length > 0
  ? Math.round(modelosOK.reduce((s, m) => s + m.confianza, 0) / modelosOK.length)
  : 0;

// ── 10. Alerta ──
const alerta =
  coincidencias >= 8 ? `🚨 ALTA COINCIDENCIA: ${coincidencias}/12` :
  coincidencias >= 4 ? `🔥 COINCIDENCIA PARCIAL: ${coincidencias}/12` :
                       `⚖️ Modelos divergen: ${coincidencias}/12`;

// ── 11. Enjaulados comunes ──
const enjauladosComunes = modeloLlama.enjaulados?.filter(n =>
  modeloMistral.enjaulados?.includes(n)
) ?? [];

// ════════════════════════════════════════════════
// OUTPUT FINAL
// ════════════════════════════════════════════════
return {
    coincidencias,
    de_total:           12,
    horas_match:        horasMatch,
    confianza_promedio: confianzaPromedio,
    alerta,
    modelos_ok:         modelosOK.length,

    // Datos para Telegram
    secuencia_consenso: secuenciaConsenso,
    modelo_lider:       modeloLider.modelo,

    // Comparativa detallada
    comparacion_horaria: comparacion,
    resultados_por_modelo: [modeloLlama, modeloMistral],
    enjaulados_comunes: enjauladosComunes,

    // Flags
    alta_coincidencia:  coincidencias >= 8,
    divergencia_total:  coincidencias === 0,
    ambos_fallaron:     modelosOK.length === 0
};
